// SubmitWaveAnswers is the resolver for the submitWaveAnswers field.
func (r *mutationResolver) SubmitWaveAnswers(ctx context.Context, waveID string, answers []*model.AnswerInput) (*model.WaveResult, error) {
	userCtx, err := requireUser(ctx)
	if err != nil {
		return nil, err
	}

	result, err := r.ProgressClient.SubmitWaveAnswers(ctx, userCtx.UserID, waveID, answers)
	if err != nil {
		return nil, err
	}

	if result.Passed {
		if userCtx.FullName == "" {
			return nil, fmt.Errorf("full name is empty in user context")
		}

		// Always update the global leaderboard.
		if _, err := r.GamificationClient.UpdateLeaderboard(ctx, userCtx.UserID, userCtx.FullName, result.TotalXp, model.LeaderboardScopeGlobal, "", nil); err != nil {
			return nil, fmt.Errorf("failed to update global leaderboard: %w", err)
		}

		// Resolve the wave's courseID for the course-scoped leaderboard.
		courseID, err := r.CourseClient.GetWaveCourseID(ctx, waveID)
		if err == nil && courseID != "" {
			if _, err := r.GamificationClient.UpdateLeaderboard(ctx, userCtx.UserID, userCtx.FullName, result.TotalXp, model.LeaderboardScopeCourse, courseID, nil); err != nil {
				return nil, fmt.Errorf("failed to update course leaderboard: %w", err)
			}
		}

		// Resolve the student's grade for the grade-scoped leaderboard
		// (grade is fetched from auth-service, NOT carried in the JWT).
		authUser, err := r.AuthClient.GetUser(ctx, userCtx.UserID)
		if err == nil && authUser.Grade != nil {
			if _, err := r.GamificationClient.UpdateLeaderboard(ctx, userCtx.UserID, userCtx.FullName, result.TotalXp, model.LeaderboardScopeGrade, "", authUser.Grade); err != nil {
				return nil, fmt.Errorf("failed to update grade leaderboard: %w", err)
			}
		}

		r.publishWaveEvents(ctx, userCtx, waveID, courseID, result)
	}

	return result, nil
}

// publishWaveEvents emits real-time wave/leaderboard events; publish
// failures never fail the submission.
func (r *mutationResolver) publishWaveEvents(ctx context.Context, userCtx middleware.UserContext, waveID, courseID string, result *model.WaveResult) {
	if r.Events == nil {
		return
	}

	_ = r.Events.Publish(ctx, events.ChannelWaveCompleted, events.WaveCompletedEvent{
		UserID:          userCtx.UserID,
		WaveID:          waveID,
		Score:           int32(result.Score),
		CompletedAtUnix: time.Now().Unix(),
	})

	scopes := []struct {
		scope    model.LeaderboardScope
		courseID string
	}{
		{model.LeaderboardScopeGlobal, ""},
	}
	if courseID != "" {
		scopes = append(scopes, struct {
			scope    model.LeaderboardScope
			courseID string
		}{model.LeaderboardScopeCourse, courseID})
	}
	for _, sc := range scopes {
		var cid *string
		if sc.courseID != "" {
			c := sc.courseID
			cid = &c
		}
		rank, err := r.GamificationClient.GetMyRank(ctx, userCtx.UserID, sc.scope, cid, nil)
		if err != nil {
			rank = 0
		}
		_ = r.Events.Publish(ctx, events.ChannelLeaderboard, events.LeaderboardUpdatedEvent{
			Scope:    string(sc.scope),
			CourseID: sc.courseID,
			UserID:   userCtx.UserID,
			FullName: userCtx.FullName,
			TotalXp:  int32(result.TotalXp),
			Rank:     int32(rank),
		})
	}
}

