// Me is the resolver for the me field.
func (r *queryResolver) Me(ctx context.Context) (*model.User, error) {
	userCtx, ok := middleware.UserFromContext(ctx)
	if !ok {
		return nil, errors.New("unauthorized")
	}

	totalXp, _ := r.GamificationClient.GetUserXp(ctx, userCtx.UserID)
	streak, _ := r.GamificationClient.GetUserStreak(ctx, userCtx.UserID)

	var grade *model.Grade
	if authUser, err := r.AuthClient.GetUser(ctx, userCtx.UserID); err == nil {
		grade = authUser.Grade
	}

	var subscription *model.UserSubscription
	if r.PaymentClient != nil {
		// A "not found" response just means the user never subscribed — not a hard error.
		if sub, err := r.PaymentClient.GetSubscription(ctx, userCtx.UserID); err == nil {
			subscription = sub
		}
	}

	return &model.User{
		ID:                userCtx.UserID,
		Email:             userCtx.Email,
		FullName:          userCtx.FullName,
		Role:              model.Role(userCtx.Role),
		Grade:             grade,
		PreferredLanguage: userCtx.PreferredLanguage,
		TotalXp:           totalXp,
		Streak:            streak,
		Subscription:      subscription,
	}, nil
}

// Courses is the resolver for the courses field.
func (r *queryResolver) Courses(ctx context.Context, filter *model.CourseFilter, pagination *model.PaginationInput) (*model.CourseConnection, error) {
	if filter == nil {
		filter = &model.CourseFilter{}
	}

	userCtx, ok := middleware.UserFromContext(ctx)
	isEducator := ok && (userCtx.Role == "EDUCATOR" || userCtx.Role == "HEAD_EDUCATOR" || userCtx.Role == "ADMIN")

	var educatorID string
	if ok && isEducator {
		educatorID = userCtx.UserID
	} else if filter.IsPublished == nil {
		published := true
		filter.IsPublished = &published
	}

	return r.CourseClient.ListCourses(ctx, filter, educatorID)
}

// MyEnrollments is the resolver for the myEnrollments field.
func (r *queryResolver) MyEnrollments(ctx context.Context) ([]*model.Course, error) {
	userCtx, err := requireUser(ctx)
	if err != nil {
		return nil, err
	}

	courses, err := r.ProgressClient.GetEnrolledCourses(ctx, userCtx.UserID)
	if err != nil {
		return nil, err
	}

	for _, course := range courses {
		progress, _ := r.ProgressClient.GetCourseProgressSummary(ctx, userCtx.UserID, course.ID)
		course.MyProgress = progress
		r.populateWavesProgress(ctx, userCtx.UserID, course)
	}

	return courses, nil
}

// Course is the resolver for the course field.
func (r *queryResolver) Course(ctx context.Context, id string) (*model.Course, error) {
	userCtx, err := requireUser(ctx)
	if err != nil {
		return nil, err
	}

	course, err := r.CourseClient.GetCourseWithLessons(ctx, id)
	if err != nil {
		return nil, err
	}

	isEducatorOrAdmin := userCtx.Role == "EDUCATOR" || userCtx.Role == "HEAD_EDUCATOR" || userCtx.Role == "ADMIN"
	if isEducatorOrAdmin {
		if userCtx.Role != "ADMIN" {
			if course.Educator == nil || course.Educator.ID != userCtx.UserID {
				return nil, errors.New("forbidden: you do not own this course")
			}
		}
	} else {
		// Student flow
		if !course.IsPublished {
			return nil, errors.New("forbidden: course is not published")
		}

		// Enrollment check removed to allow viewing course details

		// Filter out unpublished lessons and waves
		publishedLessons := make([]*model.Lesson, 0, len(course.Lessons))
		for _, lesson := range course.Lessons {
			if lesson.IsPublished {
				publishedWaves := make([]*model.Wave, 0, len(lesson.Waves))
				for _, wave := range lesson.Waves {
					if wave.IsPublished {
						publishedWaves = append(publishedWaves, wave)
					}
				}
				lesson.Waves = publishedWaves
				publishedLessons = append(publishedLessons, lesson)
			}
		}
		course.Lessons = publishedLessons
		r.populateWavesProgress(ctx, userCtx.UserID, course)
	}

	progress, _ := r.ProgressClient.GetCourseProgressSummary(ctx, userCtx.UserID, id)
	course.MyProgress = progress

	return course, nil
}

// Lesson is the resolver for the lesson field.
func (r *queryResolver) Lesson(ctx context.Context, id string) (*model.Lesson, error) {
	userCtx, err := requireUser(ctx)
	if err != nil {
		return nil, err
	}

	lesson, err := r.CourseClient.GetLessonWithWaves(ctx, id)
	if err != nil {
		return nil, err
	}

	if lesson.Course == nil {
		return nil, errors.New("lesson has no associated course")
	}

	course, err := r.CourseClient.GetCourse(ctx, lesson.Course.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to retrieve course for lesson: %w", err)
	}

	isEducatorOrAdmin := userCtx.Role == "EDUCATOR" || userCtx.Role == "HEAD_EDUCATOR" || userCtx.Role == "ADMIN"
	if isEducatorOrAdmin {
		if userCtx.Role != "ADMIN" {
			if course.Educator == nil || course.Educator.ID != userCtx.UserID {
				return nil, errors.New("forbidden: you do not own the course for this lesson")
			}
		}
	} else {
		// Student flow
		if !course.IsPublished {
			return nil, errors.New("forbidden: course is not published")
		}
		if !lesson.IsPublished {
			return nil, errors.New("forbidden: lesson is not published")
		}

		enrolled, err := r.ProgressClient.IsEnrolled(ctx, userCtx.UserID, course.ID)
		if err != nil {
			return nil, fmt.Errorf("failed to check enrollment: %w", err)
		}
		if !enrolled {
			return nil, errors.New("forbidden: not enrolled in the course for this lesson")
		}

		// Filter out unpublished waves
		publishedWaves := make([]*model.Wave, 0, len(lesson.Waves))
		for _, wave := range lesson.Waves {
			if wave.IsPublished {
				publishedWaves = append(publishedWaves, wave)
			}
		}
		lesson.Waves = publishedWaves
	}

	return lesson, nil
}

// Wave is the resolver for the wave field.
func (r *queryResolver) Wave(ctx context.Context, id string) (*model.Wave, error) {
	userCtx, err := requireUser(ctx)
	if err != nil {
		return nil, err
	}

	wave, err := r.CourseClient.GetWave(ctx, id)
	if err != nil {
		return nil, err
	}

	if wave.Lesson == nil {
		return nil, errors.New("wave has no associated lesson")
	}

	lesson, err := r.CourseClient.GetLesson(ctx, wave.Lesson.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to retrieve lesson for wave: %w", err)
	}

	if lesson.Course == nil {
		return nil, errors.New("lesson has no associated course")
	}

	course, err := r.CourseClient.GetCourse(ctx, lesson.Course.ID)
	if err != nil {
		return nil, fmt.Errorf("failed to retrieve course for wave: %w", err)
	}

	isEducatorOrAdmin := userCtx.Role == "EDUCATOR" || userCtx.Role == "HEAD_EDUCATOR" || userCtx.Role == "ADMIN"
	if isEducatorOrAdmin {
		if userCtx.Role != "ADMIN" {
			if course.Educator == nil || course.Educator.ID != userCtx.UserID {
				return nil, errors.New("forbidden: you do not own the course for this wave")
			}
		}
	} else {
		// Student flow
		if !course.IsPublished {
			return nil, errors.New("forbidden: course is not published")
		}
		if !lesson.IsPublished {
			return nil, errors.New("forbidden: lesson is not published")
		}
		if !wave.IsPublished {
			return nil, errors.New("forbidden: wave is not published")
		}

		enrolled, err := r.ProgressClient.IsEnrolled(ctx, userCtx.UserID, course.ID)
		if err != nil {
			return nil, fmt.Errorf("failed to check enrollment: %w", err)
		}
		if !enrolled {
			return nil, errors.New("forbidden: not enrolled in the course for this wave")
		}
	}

	progress, _ := r.ProgressClient.GetWaveProgress(ctx, userCtx.UserID, id)
	wave.MyProgress = progress
	wave.Lesson = lesson

	return wave, nil
}

